from dataclasses import dataclass, field
import tiktoken

@dataclass
class CompletionContext:
    prefix: str               # code before cursor
    suffix: str               # code after cursor (for FIM)
    file_path: str
    language: str
    related_snippets: list[str] = field(default_factory=list)  # from imports, open tabs
    repo_snippets: list[str] = field(default_factory=list)     # from retrieval

class ContextAssembler:
    def __init__(self, model: str = "gpt-4o", token_budget: int = 6000):
        self.encoding = tiktoken.encoding_for_model(model)
        self.budget = token_budget
        # Reservations: how many tokens each region may use
        self._prefix_max = int(token_budget * 0.50)
        self._suffix_max = int(token_budget * 0.20)
        self._related_max = int(token_budget * 0.20)
        self._repo_max = int(token_budget * 0.10)

    def _count(self, text: str) -> int:
        return len(self.encoding.encode(text))

    def _truncate_left(self, text: str, max_tokens: int) -> str:
        """Keep the LAST max_tokens tokens (most recent code)."""
        tokens = self.encoding.encode(text)
        if len(tokens) <= max_tokens:
            return text
        return self.encoding.decode(tokens[-max_tokens:])

    def _truncate_right(self, text: str, max_tokens: int) -> str:
        """Keep the FIRST max_tokens tokens."""
        tokens = self.encoding.encode(text)
        if len(tokens) <= max_tokens:
            return text
        return self.encoding.decode(tokens[:max_tokens])

    def assemble(self, ctx: CompletionContext) -> tuple[str, str]:
        """Return (prefix_prompt, suffix_prompt) ready for FIM."""
        prefix = self._truncate_left(ctx.prefix, self._prefix_max)
        suffix = self._truncate_right(ctx.suffix, self._suffix_max)

        # Prepend related snippets to prefix as comment blocks
        related_parts = []
        remaining = self._related_max
        for snippet in ctx.related_snippets:
            tokens = self._count(snippet)
            if tokens <= remaining:
                related_parts.append(snippet)
                remaining -= tokens
            if remaining <= 0:
                break

        if related_parts:
            related_block = "\n".join(
                f"# Context from {ctx.language} definitions:\n{s}"
                for s in related_parts
            )
            prefix = related_block + "\n\n" + prefix

        return prefix, suffix

import ast
import re
from pathlib import Path
from collections import defaultdict
import math

class SimpleCodeIndex:
    """Minimal BM25-style index over Python source files."""

    def __init__(self):
        self._documents: list[str] = []      # snippet text
        self._doc_names: list[str] = []      # file:symbol
        self._tf: list[dict[str, float]] = []
        self._df: dict[str, int] = defaultdict(int)

    def _tokenize(self, text: str) -> list[str]:
        return re.findall(r"[a-zA-Z_][a-zA-Z0-9_]*", text.lower())

    def add_file(self, path: Path) -> None:
        source = path.read_text(errors="replace")
        try:
            tree = ast.parse(source)
        except SyntaxError:
            return
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                snippet = ast.get_source_segment(source, node) or ""
                name = f"{path}:{node.name}"
                tokens = self._tokenize(snippet)
                tf: dict[str, float] = defaultdict(float)
                for t in tokens:
                    tf[t] += 1.0
                for t in tf:
                    tf[t] /= len(tokens)
                    self._df[t] += 1
                self._documents.append(snippet)
                self._doc_names.append(name)
                self._tf.append(tf)

    def index_project(self, root: Path) -> None:
        for py_file in root.rglob("*.py"):
            self.add_file(py_file)

    def search(self, query: str, top_k: int = 5) -> list[str]:
        """Return top-k snippet texts most relevant to query."""
        if not self._documents:
            return []
        q_tokens = set(self._tokenize(query))
        n = len(self._documents)
        scores: list[tuple[float, int]] = []
        for idx, tf in enumerate(self._tf):
            score = 0.0
            for t in q_tokens:
                if t in tf:
                    idf = math.log((n + 1) / (self._df[t] + 1))
                    score += tf[t] * idf
            scores.append((score, idx))
        top = sorted(scores, reverse=True)[:top_k]
        return [self._documents[idx] for score, idx in top if score > 0]


# Integration with ContextAssembler
def enrich_context_with_repo(
    ctx: CompletionContext,
    index: SimpleCodeIndex,
) -> CompletionContext:
    # Query the index using the last 10 identifiers visible in the prefix
    identifiers = re.findall(r"[a-zA-Z_][a-zA-Z0-9_]+", ctx.prefix)[-20:]
    query = " ".join(identifiers)
    ctx.repo_snippets = index.search(query, top_k=3)
    return ctx

from dataclasses import dataclass
from collections import defaultdict

@dataclass
class CompletionEvent:
    request_id: str
    mode: str              # "inline" | "block" | "fim"
    language: str
    latency_ms: float
    shown: bool
    accepted: bool
    tokens_generated: int
    tokens_accepted: int   # how much of the completion the user kept

class AcceptanceMetrics:
    def __init__(self):
        self._events: list[CompletionEvent] = []

    def record(self, event: CompletionEvent) -> None:
        self._events.append(event)

    def acceptance_rate(self, **filters) -> float:
        """Filter by mode/language/latency_bucket and return acceptance rate."""
        events = [e for e in self._events if e.shown]
        for key, value in filters.items():
            events = [e for e in events if getattr(e, key) == value]
        if not events:
            return 0.0
        return sum(1 for e in events if e.accepted) / len(events)

    def token_yield(self) -> float:
        """Average tokens the user actually keeps per completion shown."""
        shown = [e for e in self._events if e.shown]
        if not shown:
            return 0.0
        return sum(e.tokens_accepted for e in shown) / len(shown)

    def by_latency_bucket(self, buckets_ms: list[int] = None) -> dict[str, float]:
        """Acceptance rate broken down by latency bucket."""
        buckets = buckets_ms or [100, 200, 400, 800]
        result = {}
        prev = 0
        for ceiling in buckets + [float("inf")]:
            label = f"{prev}-{int(ceiling)}ms" if ceiling != float("inf") else f"{prev}ms+"
            bucket_events = [
                e for e in self._events
                if e.shown and prev <= e.latency_ms < ceiling
            ]
            accepted = sum(1 for e in bucket_events if e.accepted)
            result[label] = accepted / len(bucket_events) if bucket_events else 0.0
            prev = int(ceiling)
        return result
